```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {

  // Create database connection
  auto conn_result = sqlgen::sqlite::connect(db_path);

  // Handle connection result
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }

  auto conn = conn_result.value();

  // Use sqlgen's insert function to add records
  auto insert_result = sqlgen::insert(conn, records.begin(), records.end());

  // Handle insert result
  if (!insert_result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Map table names to their corresponding types
  std::map<std::string, rfl::Type> table_type_map = {
    {"Student", rfl::type_of<Student>()},
    {"Course", rfl::type_of<Course>()},
    {"Score", rfl::type_of<Score>()},
    {"Major", rfl::type_of<Major>()}
  };

  // Get the corresponding type for the table
  if (table_type_map.find(table_name) == table_type_map.end()) {
    throw std::invalid_argument("Invalid table name");
  }

  auto table_type = table_type_map[table_name];

  // Create delete statement using sqlgen's delete_from
  auto delete_stmt = sqlgen::delete_from<rfl::NamedTupleType<decltype(table_type)::ReflectionType>> 
                   | sqlgen::where("id"_c == record_id);

  // Execute the delete operation
  auto conn_result = sqlgen::sqlite::connect(db_path);

  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }

  auto conn = conn_result.value();
  auto delete_result = delete_stmt(conn);

  if (!delete_result) {
    throw std::runtime_error("Failed to delete record");
  }
}
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection with the EAS database
2. **Record Insertion**: Uses `sqlgen::insert()` function to insert records into the specified table
3. **Type Safety**: Leverages sqlgen's strong typing system through template specialization
4. **Error Handling**: Properly handles connection and operation failures
5. **Table Mapping**: Uses a type map to associate table names with their corresponding C++ structs
6. **Delete Operation**: Uses `sqlgen::delete_from()` with `sqlgen::where()` to target specific records by ID

The implementation follows sqlgen's functional programming style and properly utilizes the library's type-safe query building capabilities.

