  sqlgen::PrimaryKey<int> item_id;
  sqlgen::ForeignKey<int, Order, "order_id"> order_id;
  sqlgen::ForeignKey<int, Product, "product_id"> product_id;
  int quantity;
};

struct PurchaseHistory {
  std::string product_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  int quantity;
};

using namespace sqlgen::literals;

/**
 * Function: Retrieve a customer's purchase history with product details.
 * 
 * @param customer_id ID of the customer to query
 * @return List of purchase history items
 */
std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
    // 1. Connect to the SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // 2. Create tables by writing empty containers
    conn->write(sqlgen::write(std::vector<Customer>{}));
    conn->write(sqlgen::write(std::vector<Product>{}));
    conn->write(sqlgen::write(std::vector<Order>{}));
    conn->write(sqlgen::write(std::vector<OrderItem>{}));

    // 3. Build the query using sqlgen::read with pipe operators
    auto query = sqlgen::read<std::vector<PurchaseHistory>>
        | sqlgen::inner_join<Customer, "c">("c.customer_id"_c == "o.customer_id"_c)
        | sqlgen::inner_join<Order, "o">("o.order_id"_c == "oi.order_id"_c)
        | sqlgen::inner_join<OrderItem, "oi">("oi.product_id"_c == "p.product_id"_c)
        | sqlgen::inner_join<Product, "p">("p.name"_c.as<"product_name">() == "p.name"_c)
        | sqlgen::where("c.customer_id"_c == customer_id)
        | sqlgen::order_by("o.order_date"_c.desc());

    // 4. Execute the query and return results
    return query(*conn).value();
}

}  // namespace query_customer_purchase_history
