#include <vector>

namespace query_daily_traffic_metrics {

struct PageVisit {
  sqlgen::PrimaryKey<int> visit_id;
  std::string url;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> visit_time;
};

struct DailyTraffic {
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

struct DailyTrafficView {
  static constexpr const char* tablename = "DailyTrafficView";
  static constexpr bool is_view = true;
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

std::vector<DailyTraffic> query_daily_traffic_metrics() {
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Build the query using sqlgen's fluent interface
  auto query = sqlgen::select_from<PageVisit>(
      sqlgen::strftime("%Y-%m-%d", &PageVisit::visit_time).as<"visit_date">(),
      sqlgen::count().as<"total_visits">(),
      sqlgen::count_distinct(&PageVisit::url).as<"unique_pages">()
  )
  .group_by(sqlgen::strftime("%Y-%m-%d", &PageVisit::visit_time))
  .order_by(sqlgen::strftime("%Y-%m-%d", &PageVisit::visit_time));

  // Execute the query and convert results to vector<DailyTraffic>
  auto result = query(conn);

  // Transform the range of named tuples to vector<DailyTraffic>
  std::vector<DailyTraffic> traffic_metrics;
  for (auto& row : result.value()) {
    traffic_metrics.push_back(DailyTraffic{
        .visit_date = std::move(row.visit_date),
        .total_visits = std::move(row.total_visits),
        .unique_pages = std::move(row.unique_pages)
    });
  }

  return traffic_metrics;
}

}  // namespace query_daily_traffic_metrics
```

