```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // Start transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return false;
  }

  try {
    // Check if from_account has sufficient balance
    auto from_account = read<Account> | where("account_id"_c == from_account_id);
    auto result = from_account(*conn);
    if (!result) {
      conn->rollback();
      return false;
    }

    auto& account = result.value();
    if (account.balance < amount) {
      conn->rollback();
      return false;
    }

    // Update from_account: balance = balance - amount
    auto update_from = update<Account>("balance"_c.set("balance"_c - amount)) 
                      | where("account_id"_c == from_account_id && "balance"_c >= amount);
    auto update_result = update_from(*conn);
    if (!update_result) {
      conn->rollback();
      return false;
    }

    // Update to_account: balance = balance + amount
    auto update_to = update<Account>("balance"_c.set("balance"_c + amount)) 
                    | where("account_id"_c == to_account_id);
    auto update_to_result = update_to(*conn);
    if (!update_to_result) {
      conn->rollback();
      return false;
    }

    // Commit transaction
    auto commit_result = conn->commit();
    if (!commit_result) {
      conn->rollback();
      return false;
    }

    return true;

  } catch (...) {
    // Rollback on any exception
    conn->rollback();
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Transaction Management**: 
   - Starts transaction with `begin_transaction()`
   - Commits with `commit()` on success
   - Rolls back with `rollback()` on failure

3. **Balance Check**: Uses `read<Account>` with `where` clause to check if `from_account` has sufficient balance

4. **Parameterized Updates**: Uses sqlgen's update syntax with column operations:
   - `"balance"_c.set("balance"_c - amount)` for subtraction
   - `"balance"_c.set("balance"_c + amount)` for addition

5. **Condition Checks**: Includes both account ID and balance checks in the WHERE clauses

6. **Error Handling**: Properly handles all Result types and ensures rollback on any failure

The implementation follows sqlgen's fluent API pattern and properly handles all the transaction safety requirements specified in the assessment objectives.

