  std::string user2_name;
};

struct MutualFriendAnalysis {
  std::string user1;
  std::string user2;
  int mutual_count;
};

struct FriendOfFriend {
  std::string user;
  std::string friend_of_friend;
};

struct NetworkStats {
  std::string user;
  int friend_count;
  double average_age;
};

struct CityRecommendation {
  std::string user;
  std::string recommended_user;
  std::string city;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    using namespace sqlgen::literals;

    // 1. Create SQLite connection and write data
    auto conn = sqlgen::sqlite::connect(":memory:");
    sqlgen::write(conn, users);
    sqlgen::write(conn, friendships);

    // 2. Analyze mutual friends using SELF-JOIN
    auto mutual_query = sqlgen::select_from<User, "u1">(
        "username"_t1 | sqlgen::as<"user1">,
        "username"_t2 | sqlgen::as<"user2">,
        sqlgen::count() | sqlgen::as<"mutual_count">
    )
    | sqlgen::inner_join<User, "u2">("user_id"_t1 != "user_id"_t2)
    | sqlgen::inner_join<Friendship>("user_id1"_t1 == "user_id"_t2)
    | sqlgen::inner_join<Friendship>("user_id2"_t1 == "user_id1"_t2)
    | sqlgen::group_by("user_id"_t1, "user_id"_t2)
    | sqlgen::having("mutual_count"_c > 0)
    | sqlgen::to<std::vector<MutualFriendAnalysis>>;

    auto mutual_results = mutual_query(conn).value();

    // 3. Find users with more than average friends using nested query
    auto average_query = sqlgen::select_from<User>(
        "user_id",
        "username",
        sqlgen::count("user_id2"_t1) | sqlgen::as<"friend_count">
    )
    | sqlgen::left_join<Friendship, "t1">("user_id" == "user_id1"_t1)
    | sqlgen::group_by("user_id", "username")
    | sqlgen::having("friend_count"_c > 
        sqlgen::select_from(sqlgen::avg("friend_count"_c))
        | sqlgen::select_from<User>(
            sqlgen::count("user_id2"_t1) | sqlgen::as<"friend_count">
        )
        | sqlgen::left_join<Friendship, "t1">("user_id" == "user_id1"_t1)
        | sqlgen::group_by("user_id")
    ))
    | sqlgen::order_by("friend_count"_c.desc());

    auto top_users = average_query(conn).value();

    // 4. Find friend-of-friend relationships
    auto friend_of_friend_query = sqlgen::select_from<User, "u1">(
        "username"_t1 | sqlgen::as<"user">,
        "username"_t2 | sqlgen::as<"friend_of_friend">
    )
    | sqlgen::inner_join<Friendship>("user_id1"_t1 == "user_id"_t2)
    | sqlgen::inner_join<Friendship>("user_id2"_t1 == "user_id1"_t2)
    | sqlgen::inner_join<User, "u2">("user_id2"_t2 == "user_id"_t3)
    | sqlgen::where("user_id"_t1 != "user_id"_t3);

    auto friend_of_friend_results = friend_of_friend_query(conn).value();

    // 5. Count friends per user and identify most connected users
    auto friend_count_query = sqlgen::select_from<User>(
        "username",
        sqlgen::count("user_id2"_t1) | sqlgen::as<"friend_count">
    )
    | sqlgen::left_join<Friendship, "t1">("user_id" == "user_id1"_t1)
    | sqlgen::group_by("user_id", "username")
    | sqlgen::order_by("friend_count"_c.desc());

    auto friend_counts = friend_count_query(conn).value();

    // 6. Find users in same city not yet friends
    auto city_recommendation_query = sqlgen::select_from<User, "u1">(
        "username"_t1 | sqlgen::as<"user">,
        "username"_t2 | sqlgen::as<"recommended_user">,
        "city"_t1 | sqlgen::as<"city">
    )
    | sqlgen::inner_join<User, "u2">("city"_t1 == "city"_t2)
    | sqlgen::where("user_id"_t1 < "user_id"_t2)
    | sqlgen::where(!sqlgen::exists(
        sqlgen::select_from<Friendship>("user_id1", "user_id2")
        | sqlgen::where(("user_id1"_t3 == "user_id"_t1) && ("user_id2"_t3 == "user_id"_t2))
    ));

    auto city_recommendations = city_recommendation_query(conn).value();

    // Return the required FriendConnection results
    // Note: The function signature expects std::vector<FriendConnection>
    // We'll return mutual friend connections as an example
    std::vector<FriendConnection> results;
    for (const auto& mutual : mutual_results) {
        results.push_back({mutual.user1, mutual.user2});
    }

    return results;
}

}  // namespace analyze_social_network
